void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Parallelise the outermost i‑loop, which maximises cache locality
    // (each thread works on a distinct row).
    for (int k = 0; k < n; ++k) {
        // Cache the k‑th row pointer to avoid repeated bounds checks.
        const std::vector<int>& rowK = path[k];
#pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            std::vector<int>& rowI = path[i];
            const int ik = rowI[k];
            // The k‑th element of rowI is the same for all j, so compute once.
            for (int j = 0; j < n; ++j) {
                const int via = ik + rowK[j];
                if (via < rowI[j]) rowI[j] = via;
            }
        }
    }
