       enough that a static schedule gives good load balance on 8 cores. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tpr = 0.0;          // local accumulator for tmp[i]
        double yr  = 0.0;          // local accumulator for y[i]
        const double* Ai = A[i].data();
        const double* Bi = B[i].data();
        const double* X  = x.data();

        /* Unroll a small factor to reduce branch overhead and
           give the compiler a better chance for vectorisation. */
        int j = 0;
        const int unroll = 8;
        for (; j <= n - unroll; j += unroll) {
#pragma unroll
            for (int k = 0; k < unroll; ++k) {
                int idx = j + k;
                tpr += Ai[idx] * X[idx];
                yr  += Bi[idx] * X[idx];
            }
        }
        for (; j < n; ++j) {
            tpr += Ai[j] * X[j];
            yr  += Bi[j] * X[j];
        }

        tmp[i] = tpr;
        y[i]   = alpha * tpr + beta * yr;
