void kernel_seidel_2d(int tsteps, int n, std::vector<std::vector<double>>& A)
{
    const double inv9 = 1.0 / 9.0;                 // pre‑compute reciprocal

    /* Parallelise over both i and t dimensions to keep thread cache
       utilisation high.  The outer loop (time) must be outside the
       OpenMP region because each time step depends on the previous one. */
    for (int t = 0; t < tsteps; ++t) {

        /* collapse(2) merges the two nested loops (i, j) into one
           parallel loop.  schedule(static) gives each thread a block
           of consecutive i‑rows.  This avoids load imbalance in
           small sub‑sweeps. */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            /* Local pointers to the neighbouring rows */
            const double* row_up   = A[i - 1].data();
            const double* row_cur  = A[i].data();
            const double* row_down = A[i + 1].data();

            for (int j = 1; j <= n - 2; ++j) {
                /* 3×3 stencil average */
                row_cur[j] = (row_up[j - 1]   + row_up[j]   + row_up[j + 1] +
                              row_cur[j - 1] + row_cur[j] + row_cur[j + 1] +
                              row_down[j - 1] + row_down[j] + row_down[j + 1]) * inv9;
            }
        }
    }
}
