void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    // Work on raw pointers for better SIMD / register usage
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();               // pointer to current row i

        // Compute the strictly lower part of the row i
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            const double* Aj = A[j].data();    // pointer to row j
            const int jlim = j;

            // Inner dot–product loop
            #pragma GCC ivdep
            for (int k = 0; k < jlim; ++k) {
                sum += Ai[k] * Aj[k];
            }

            Ai[j] = (Ai[j] - sum) / Aj[j];
        }

        // Compute the diagonal entry
        double sum = 0.0;
        #pragma GCC ivdep
        for (int k = 0; k < i; ++k) {
            double v = Ai[k];
            sum += v * v;
        }
        Ai[i] = std::sqrt(Ai[i] - sum);
    }
}
