void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Flatten the 2‑D vector data for faster access
    double* Cptr = &C[0][0];
    double* Aptr = &A[0][0];

    // Cache‑line friendly blocking of the j‑loop
    const int block = 64; // tune this for your architecture

    // Parallelise over rows of C
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // offset to the i‑th row in C and A
        double* Crow = Cptr + i * n;
        double* Arrow = Aptr + i * m;

        // Scale the lower triangle of the i‑th row by beta
        for (int j = 0; j <= i; ++j) {
            Crow[j] *= beta;
        }

        // Main SUMMA‑style accumulation
        for (int k = 0; k < m; ++k) {
            double aik = Arrow[k];
            // block‑wise j‑loop for better cache behaviour
            for (int j = 0; j <= i; j += block) {
                int jmax = (j + block <= i) ? j + block : i + 1;
                double* ptrC = Crow + j;
                double* ptrA = Aptr + j * m; // A[j][k]
                for (int jj = j; jj < jmax; ++jj) {
                    *ptrC += alpha * aik * ptrA[jj * m + k];
                }
            }
        }
    }
}
