    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // 1) scale the lower‑triangular part of C by beta
        for (int j = 0; j <= i; ++j) {
            C[i][j] *= beta;
        }

        // 2) perform the rank‑2k update
        // The innermost loop is over the lower triangle,
        // so we keep that order to preserve the original
        // computation and memory access pattern.
        for (int k = 0; k < m; ++k) {
            // Pre‑multiply by alpha to avoid repeated work.
            double a_jk_alpha = alpha * A[j][k];   // will be used inside inner loop
            double a_ik_alpha = alpha * A[i][k];
            for (int j = 0; j <= i; ++j) {
                double b_ik = B[i][k];
                double b_jk = B[j][k];
                C[i][j] += A[j][k]*a_ik_alpha + a_jk_alpha * b_ik;
            }
        }
    }
}
