    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            cov[i][j] = sum / (static_cast<double>(n) - 1.0);
            cov[j][i] = cov[i][j];
