/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Number of threads is automatically chosen by OpenMP.
       Parallelise the outer loops of both matrix multiplications.
       The matrices are assumed to be row‑major contiguous
       which is guaranteed by std::vector< std::vector<double> >. */

    /* Temporary pointer access for speed */
    const int TILE = 32;                     // block size tuned for cache

    /* 1st GEMM:  tmp = alpha * A * B   (ni x nj = ni x nk * nk x nj) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += TILE) {
        for (int jj = 0; jj < nj; jj += TILE) {
            for (int i = ii; i < std::min(ii + TILE, ni); ++i) {
                for (int j = jj; j < std::min(jj + TILE, nj); ++j) {
                    double acc = 0.0;
                    for (int k = 0; k < nk; ++k) {
                        acc += alpha * A[i][k] * B[k][j];
                    }
                    tmp[i][j] = acc;
                }
            }
        }
    }

    /* 2nd GEMM:  D = beta * D + tmp * C   (ni x nl = ni x nj * nj x nl) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += TILE) {
        for (int jj = 0; jj < nl; jj += TILE) {
            for (int i = ii; i < std::min(ii + TILE, ni); ++i) {
                for (int j = jj; j < std::min(jj + TILE, nl); ++j) {
                    double acc = beta * D[i][j];
                    for (int k = 0; k < nj; ++k) {
                        acc += tmp[i][k] * C[k][j];
                    }
                    D[i][j] = acc;
