#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    constexpr double eps = 0.1;
    const double sqn = std::sqrt(static_cast<double>(n));

    /* ---------- mean ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += data[i][j];
        mean[j] = sum / n;
    }

    /* ---------- stddev ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double ss = 0.0;
        double mj = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mj;
            ss += d * d;
        }
        stddev[j] = std::sqrt(ss / n);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ---------- normalize data ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = (data[i][j] - mean[j]) / (sqn * stddev[j]);
            data[i][j] = val;
        }
    }

    /* ---------- correlation matrix ---------- */
    /* symmetric, only compute upper triangle */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
