        const double* arow = A[i].data();         // row i of A
        const double ai_diag = arow[i] * alpha;    // A[i][i] * alpha

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            const double bij = brow[j] * alpha;   // B[i][j] * alpha

            // Accumulate contribution from k < i
