    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        double* ai = A[i].data();
#pragma omp simd reduction(-: w)
        for (int j = 0; j < i; ++j)
            w -= ai[j] * y[j];
        y[i] = w;
    }

    /* Backward substitution x = U^{-1} y */
    for (int i = n - 1; i >= 0; --i)
    {
        double w = y[i];
        double* ai = A[i].data();
#pragma omp simd reduction(-: w)
        for (int j = i + 1; j < n; ++j)
            w -= ai[j] * x[j];
