/*
 * Optimised Durbin kernel – no change in API or semantics.
 * Uses raw pointers, loop unrolling and AVX2 where possible.
 * @param n  length of the autocorrelation vector r
 * @param r  input autocorrelation vector
 * @param y  output reflection coefficients (overwritten)
 */
void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y)
{
    // Allocate temporary buffer once
    std::vector<double> z(n);

    // Work with raw pointers for speed
    const double* rp = r.data();
          double* yp = y.data();
          double* zp = z.data();

    yp[0] = -rp[0];
    double beta  = 1.0;
    double alpha = -rp[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1]*y[i]
        double sum = 0.0;
        int i = 0;
        // AVX2 vectorized accumulation (2 doubles per 256‑bit register)
        __m128d vsum0 = _mm_setzero_pd();
        __m128d vsum1 = _mm_setzero_pd();
        for (; i <= k - 4; i += 4) {
            __m128d vr0 = _mm_loadu_pd(rp + k - i - 1);
            __m128d vr1 = _mm_loadu_pd(rp + k - i - 3);
            __m128d vy0 = _mm_loadu_pd(yp + i);
            __m128d vy1 = _mm_loadu_pd(yp + i + 2);
            vsum0 = _mm_fmadd_pd(vr0, vy0, vsum0);
            vsum1 = _mm_fmadd_pd(vr1, vy1, vsum1);
        }
        // horizontal add of vector sums
        vsum0 = _mm_add_pd(vsum0, vsum1);
        sum += _mm_cvtsd_f64(vsum0) + _mm_cvtsd_f64(_mm_unpackhi_pd(vsum0, vsum0));

        // remaining scalar elements
        for (; i < k; ++i) sum += rp[k - i - 1] * yp[i];

        alpha = -(rp[k] + sum) / beta;

        // Compute z[i] = y[i] + alpha*y[k-i-1]
        for (i = 0; i < k; ++i) {
            zp[i] = yp[i] + alpha * yp[k - i - 1];
        }

        // Copy z back to y (avoids extra temp)
        std::memcpy(yp, zp, k * sizeof(double));

        yp[k] = alpha;
    }
}
