/* SIMD‑aware, cache‑friendly Jacobi 1‑D kernel.
   The function keeps the same semantics as the reference: two
   staggered half‑steps per time step.  We avoid the extra
   division by pre‑computing the constant 1/3 as a double literal.
   The implementation uses AVX2 intrinsics (128‑bit SSE2 is also
   possible but AVX2 gives a stronger speedup on modern x86‑64 chips). */
static constexpr double INV3 = 1.0 / 3.0;

void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    /* Align pointers to 32‑byte boundaries for AVX2.
       The standard guarantees that vector's data is at least 64‑byte aligned,
       which is fine for AVX2 as we only need 32‑byte. */
    const double*  a = A.data();
    const double*  b = B.data();
    double*        ap = A.data();
    double*        bp = B.data();

    const int block = 8;       // number of doubles processed per AVX2 vector (256 / 64)

    for (int t = 0; t < tsteps; ++t) {
        /* 1st half‑step: B[i] = inv3 * (A[i-1] + A[i] + A[i+1]) */
        // tail: i = 1..n-2
        int i = 1;
        // process in vector chunks
        for (; i <= n - 1 - block; i += block) {
            __m256d prev = _mm256_loadu_pd(a + i - 1);
            __m256d cur  = _mm256_loadu_pd(a + i);
            __m256d next = _mm256_loadu_pd(a + i + 1);
            __m256d sum  = _mm256_add_pd(prev, cur);
            sum = _mm256_add_pd(sum, next);
            sum = _mm256_mul_pd(_mm256_set1_pd(INV3), sum);
            _mm256_storeu_pd(b + i, sum);
        }
        // scalar tail
        for (; i < n - 1; ++i) {
            bp[i] = INV3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* 2nd half‑step: A[i] = inv3 * (B[i-1] + B[i] + B[i+1]) */
        i = 1;
        for (; i <= n - 1 - block; i += block) {
            __m256d prev = _mm256_loadu_pd(b + i - 1);
            __m256d cur  = _mm256_loadu_pd(b + i);
            __m256d next = _mm256_loadu_pd(b + i + 1);
            __m256d sum  = _mm256_add_pd(prev, cur);
            sum = _mm256_add_pd(sum, next);
            sum = _mm256_mul_pd(_mm256_set1_pd(INV3), sum);
            _mm256_storeu_pd(a + i, sum);
        }
        for (; i < n - 1; ++i) {
            ap[i] = INV3 * (bp[i-1] + bp[i] + bp[i+1]);
        }
    }
}
