    const int innerStart = 1;
    const int innerEnd   = n - 2;        // last index < n-1

    for (int t = 1; t <= tsteps; ++t)
    {
        /* ----------------------------------------------------
           First update B from A (forward sweep)
           ---------------------------------------------------- */
