        for (int i = innerStart; i <= innerEnd; ++i)
            for (int j = innerStart; j <= innerEnd; ++j)
                for (int k = innerStart; k <= innerEnd; ++k)
                {
                    double aCenter = A[i][j][k];
                    double sum = 0.0;

                    // X
                    sum += A[i+1][j][k] + A[i-1][j][k];
                    // Y
                    sum += A[i][j+1][k] + A[i][j-1][k];
                    // Z
                    sum += A[i][j][k+1] + A[i][j][k-1];

                    B[i][j][k] = coef * (sum - 6.0 * aCenter) + aCenter;
                }

        /* ----------------------------------------------------
           Second update A from B (backward sweep)
           ---------------------------------------------------- */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = innerStart; i <= innerEnd; ++i)
            for (int j = innerStart; j <= innerEnd; ++j)
                for (int k = innerStart; k <= innerEnd; ++k)
                {
                    double bCenter = B[i][j][k];
