    // 2) Main double‑loop.
    //    We parallelise over the outer index i.  Inside the loop the
    //    inner loop is small enough to profit from spatial locality,
    //    so we keep it as a simple run‑of‑the‑mill loop.
    // --------------------------------------------------------------------
#pragma omp parallel for schedule(dynamic, 64)   // tiles of 64 rows for load balancing
    for (int i = 0; i < n; ++i) {
        const double ri = r[i];
        const std::vector<double>& Ai = A[i];          // row of A
        double qi = 0.0;                               // local accumulator for q[i]
        for (int j = 0; j < m; ++j) {
            //  s[j] and q[i] are independent for this i; we can
            //  update them directly.  The write to s[j] is a
            //  potential false sharing hotspot, but the rows of A
            //  are usually large enough that the overhead of a
            //  reduction is higher.
