void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Treat the 2‑D vector as a flat array for better cache locality.
    double *p   = &A[0][0];
    const int stride = n;

    for (int i = 0; i < n; ++i) {
        double *rowi = p + i * stride;

