           has an intra‑row dependency (A[i][j] requires A[j][j]),
           so it must stay sequential. */
        for (int j = 0; j < i; ++j) {
            double val = rowi[j];
            for (int k = 0; k < j; ++k)
                val -= rowi[k] * (p + k * stride)[j];
            rowi[j] = val / (p + j * stride)[j];
        }

        /* Update the remaining part of the row.
           Here the updates for different columns j are independent,
           so we parallelise this loop with OpenMP. */
#pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k)
                sum += rowi[k] * (p + k * stride)[j];
            rowi[j] -= sum;
