                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_)
{
    const std::size_t nx_ = static_cast<std::size_t>(nx);
    const std::size_t ny_ = static_cast<std::size_t>(ny);
    const std::size_t stride = ny_;

    // Flatten the 2-D arrays into 1-D buffers for fast access
    std::vector<double> ex_buf(nx_ * ny_);
    std::vector<double> ey_buf(nx_ * ny_);
    std::vector<double> hz_buf(nx_ * ny_);

    for(std::size_t i = 0; i < nx_; ++i)
        for(std::size_t j = 0; j < ny_; ++j) {
            std::size_t idx = i * stride + j;
            ex_buf[idx] = ex[i][j];
            ey_buf[idx] = ey[i][j];
            hz_buf[idx] = hz[i][j];
        }

#pragma omp parallel
    {
        for(int t = 0; t < tmax; ++t) {
            // 1) ey[0][j] = _fict_[t]
#pragma omp for
            for(std::size_t j = 0; j < ny_; ++j)
                ey_buf[j] = _fict_[t];

            // 2) Update ey for i > 0
#pragma omp for collapse(2)
            for(std::size_t i = 1; i < nx_; ++i)
                for(std::size_t j = 0; j < ny_; ++j) {
                    std::size_t idx = i * stride + j;
                    ey_buf[idx] -= 0.5 * (hz_buf[idx] - hz_buf[(i - 1) * stride + j]);
                }

            // 3) Update ex
#pragma omp for collapse(2)
            for(std::size_t i = 0; i < nx_; ++i)
                for(std::size_t j = 1; j < ny_; ++j) {
                    std::size_t idx = i * stride + j;
                    ex_buf[idx] -= 0.5 * (hz_buf[idx] - hz_buf[i * stride + (j - 1)]);
