            // 4) Update hz
#pragma omp for collapse(2)
            for(std::size_t i = 0; i < nx_ - 1; ++i)
                for(std::size_t j = 0; j < ny_ - 1; ++j) {
                    std::size_t idx = i * stride + j;
                    hz_buf[idx] -= 0.7 *
