/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    // Match function: returns 1 if complementary (sum == 3), else 0
    auto match = [](int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; };

    /*
     * The DP dependency graph is anti‑diagonal:
     * table[i][j] depends only on entries with
     *  (i', j') such that i' >= i and j' <= j, with a smaller
     *  difference j'-i'.  Consequently, all cells of a fixed
     *  diagonal d = j-i can be updated independently.
     *
     * We parallelise over those diagonals.  The outer loop runs
     * over increasing diagonal lengths, provoking a natural
     * forward direction.  The inner loop iterates over each possible
     * i for that diagonal; the body is completely independent of other
     * iterations on the same diagonal, so an
     * #pragma omp for is safe.
     */

#pragma omp parallel for schedule(dynamic)
    for (int d = 1; d < n; ++d) {             // d = j - i
        for (int i = 0; i + d < n; ++i) {     // start index
            int j = i + d;                   // end index
            int best = table[i][j];          // current value (initialised to 0)

            // 1. table[i][j-1]
            if (j - 1 >= 0)
                best = std::max(best, table[i][j - 1]);

            // 2. table[i+1][j]
            if (i + 1 < n)
                best = std::max(best, table[i + 1][j]);

            // 3. table[i+1][j-1] (with or without a match)
            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1)
                    best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
                else
                    best = std::max(best, table[i + 1][j - 1]);
            }

            // 4. Split the interval at every k
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, table[i][k] + table[k + 1][j]);
            }

            table[i][j] = best;
        }
    }
}
