#include <cmath>
#include <vector>
#include <omp.h>

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute coefficients once */
    const float expA = std::exp(-alpha);
    const float exp2A = std::exp(-2.0 * alpha);
    const float denom = 1.0f + 2.0f * static_cast<float>(alpha) * expA - exp2A;
    const float k = 1.0f - static_cast<float>(expA * (1.0 - expA) / denom);

    const float a1 = k;
    const float a2 = k * expA * (static_cast<float>(alpha) - 1.0f);
    const float a3 = k * expA * (static_cast<float>(alpha) + 1.0f);
    const float a4 = -k * exp2A;
    const float a5 = k;
    const float a6 = k * expA * (static_cast<float>(alpha) - 1.0f);
    const float a7 = k * expA * (static_cast<float>(alpha) + 1.0f);
    const float a8 = -k * exp2A;

    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp2A;
    const float c1 = 1.0f;
    const float c2 = 1.0f;

    /* ---------- forward pass along rows ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f;
        float xm1 = 0.0f;
        float* in  = imgIn[i].data();
        float* out = y1[i].data();
        for (int j = 0; j < h; ++j) {
            const float v = in[j];
            out[j] = a1 * v + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = v;
            ym2 = ym1;
            ym1 = out[j];
        }
    }

    /* ---------- backward pass along rows ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;
        float* in  = imgIn[i].data();
        float* out = y2[i].data();
        for (int j = h - 1; j >= 0; --j) {
            const float v = in[j];
            out[j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = v;
            yp2 = yp1;
            yp1 = out[j];
        }
    }

    /* ---------- combine first and second half along rows ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            const float sum = y1[i][j] + y2[i][j];
            imgOut[i][j] = c1 * sum;
        }
    }

    /* ---------- forward pass along columns ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float v = imgOut[i][j];
            y1[i][j] = a5 * v + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = v;
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* ---------- backward pass along columns ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float v = imgOut[i][j];
            y2[i][j] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = v;
            yp2 = yp1;
            yp1 = y2[i][j];
        }
    }

    /* ---------- final accumulation ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
