#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;

    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    // Pre‑allocate row pointers to avoid repeated bounds checks
    std::vector<double*> uRow(n), vRow(n), pRow(n), qRow(n);
    for (int i = 0; i < n; ++i) {
        uRow[i] = u[i].data();
        vRow[i] = v[i].data();
        pRow[i] = p[i].data();
        qRow[i] = q[i].data();
    }

    #pragma omp parallel
    {
        for (int t = 1; t <= tsteps; ++t) {
            /* ----- first sweep : compute v from u ----- */
            #pragma omp for schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double* const ui = uRow[i];
                double* const vi = vRow[i];
                double* const pi = pRow[i];
                double* const qi = qRow[i];

                vi[0] = 1.0;
                pi[0] = 0.0;
                qi[0] = vi[0];      // same as 1.0

                for (int j = 1; j < n - 1; ++j) {
                    const double denom = a * pi[j-1] + b;
                    pi[j] = -c / denom;

                    const double num = -d * ui[j-1]
                                     + (1.0 + 2.0 * d) * ui[j]
                                     - f * ui[j+1]
                                     - a * qi[j-1];
                    qi[j] = num / denom;
                }

                vi[n-1] = 1.0;

                for (int j = n - 2; j >= 1; --j) {
                    vi[j] = pi[j] * vi[j+1] + qi[j];
                }
            }

            /* ----- second sweep : compute u from v ----- */
            #pragma omp for schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double* const ui = uRow[i];
                double* const vi = vRow[i];
                double* const pi = pRow[i];
                double* const qi = qRow[i];

                ui[0] = 1.0;
                pi[0] = 0.0;
                qi[0] = ui[0];

                for (int j = 1; j < n - 1; ++j) {
                    const double denom = d * pi[j-1] + e;
                    pi[j] = -f / denom;

                    const double num = -a * vi[i-1][j]
                                     + (1.0 + 2.0 * a) * vi[i][j]
                                     - c * vi[i+1][j]
                                     - d * qi[j-1];
                    qi[j] = num / denom;
                }

                ui[n-1] = 1.0;

                for (int j = n - 2; j >= 1; --j) {
                    ui[j] = pi[j] * ui[j+1] + qi[j];
                }
            }
        } // end of time steps
    }     // end of parallel region
}
